  switch (status.kind) {
    case 'pending':  return 'Waiting...';
    case 'success':  return `Value: ${status.value}`;
    case 'error':    return `Error: ${status.message}`;
    default: {
      // Если добавить { kind: 'cancelled' } в Status без соответствующего case,
      // TypeScript выдаст ошибку: "Type 'never' has no construct signatures"
      const _exhaustive: never = status;
      return _exhaustive;
    }
  }
}

// Вариант: вынести в вспомогательную функцию для runtime-защиты тоже
